import{_ as a,o as t,c as s,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"User manual","description":"How to run cleanup and file recovery scans, read results, preview media, and clean or copy out safely with Aerosol.","frontmatter":{"title":"User manual","description":"How to run cleanup and file recovery scans, read results, preview media, and clean or copy out safely with Aerosol."},"headers":[],"relativePath":"manual.md","filePath":"manual.md","lastUpdated":1775592403000}'),n={name:"manual.md"};function o(i,e,l,d,c,h){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="user-manual" tabindex="-1">User manual <a class="header-anchor" href="#user-manual" aria-label="Permalink to &quot;User manual&quot;">​</a></h1><p>How to run a scan, read results, clean up safely, and use <strong>File recovery</strong> when you need read-only discovery and copy-out.</p><h2 id="macos-install-github-release-builds" tabindex="-1">macOS install (GitHub release builds) <a class="header-anchor" href="#macos-install-github-release-builds" aria-label="Permalink to &quot;macOS install (GitHub release builds)&quot;">​</a></h2><p><strong>Apple Silicon (M1 / M2 / M3)</strong> — download the <strong>aarch64</strong> or <strong>arm64</strong> <code>.dmg</code> from the <a href="https://github.com/januscaler/aerosol/releases/latest" target="_blank" rel="noreferrer">latest release</a>, not the <strong>x86_64</strong> one (that build is for Intel Macs).</p><h3 id="aerosol-is-damaged-and-can-t-be-opened" tabindex="-1">“Aerosol” is damaged and can’t be opened <a class="header-anchor" href="#aerosol-is-damaged-and-can-t-be-opened" aria-label="Permalink to &quot;“Aerosol” is damaged and can’t be opened&quot;">​</a></h3><p>That message usually means <strong>Gatekeeper</strong> blocked an <strong>unsigned</strong> app (it is often <strong>not</strong> a corrupted download). Try, in order:</p><ol><li><p><strong>Right-click</strong> <code>Aerosol.app</code> → <strong>Open</strong> → confirm <strong>Open</strong> (first launch only).</p></li><li><p><strong>System Settings</strong> → <strong>Privacy &amp; Security</strong> → scroll to the message about Aerosol → <strong>Open Anyway</strong>.</p></li><li><p>In <strong>Terminal</strong>, clear the download quarantine flag (after copying the app to <strong>Applications</strong>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/Aerosol.app</span></span></code></pre></div><p>If you are still running from the mounted <code>.dmg</code>, use the path to the <code>.app</code> inside the disk image instead.</p></li></ol><p>For a build that is trusted system-wide without those steps, the publisher must use an <strong>Apple Developer ID</strong> certificate and <strong>notarization</strong> (<a href="https://v2.tauri.app/distribute/sign/macos/" target="_blank" rel="noreferrer">Tauri macOS signing</a>).</p><h2 id="first-launch" tabindex="-1">First launch <a class="header-anchor" href="#first-launch" aria-label="Permalink to &quot;First launch&quot;">​</a></h2><p>Open the app and use the header to choose <strong>Cleanup</strong> or <strong>File recovery</strong>. For cleanup, review <strong>Settings → Preferences</strong> if you want to change scan scope, extra roots, or time budget. For recovery defaults (scan mode, max files, remembered output folder), use <strong>Settings → File recovery</strong>. Defaults favor a quick, practical cleanup pass over your home (and related) locations.</p><h2 id="running-a-scan" tabindex="-1">Running a scan <a class="header-anchor" href="#running-a-scan" aria-label="Permalink to &quot;Running a scan&quot;">​</a></h2><ol><li>Click <strong>Scan</strong> and wait for the progress phase to finish.</li><li>When the scan completes, a summary shows counts and the largest files surfaced for this run.</li><li>Large scans stay paginated so the UI does not load every row at once.</li></ol><h2 id="understanding-filters" tabindex="-1">Understanding filters <a class="header-anchor" href="#understanding-filters" aria-label="Permalink to &quot;Understanding filters&quot;">​</a></h2><ul><li><strong>All</strong> — every finding from the current scan.</li><li><strong>Safe</strong> — items classified as safer to remove (still review if unsure).</li><li><strong>Review</strong> — items that may deserve a closer look before deletion.</li></ul><h2 id="selection-and-cleanup" tabindex="-1">Selection and cleanup <a class="header-anchor" href="#selection-and-cleanup" aria-label="Permalink to &quot;Selection and cleanup&quot;">​</a></h2><ul><li>Use checkboxes to select individual paths, or select the visible page.</li><li><strong>Select all safe</strong> loads every safe path from the scan into the selection (useful for bulk cleanup).</li><li><strong>Preview only (dry run)</strong> estimates space without deleting; turn it off to perform real cleanup.</li><li><strong>Move to Trash when possible</strong> sends removals to the system Trash where supported instead of immediate permanent delete.</li><li>Cleanup merges nested selections (for example a folder and files inside it) into minimal delete operations to reduce redundant work and prompts.</li><li>Progress is shown during deletion; after a real cleanup, the list and summary refresh from the pruned cache.</li></ul><h2 id="large-files-duplicates" tabindex="-1">Large files &amp; duplicates <a class="header-anchor" href="#large-files-duplicates" aria-label="Permalink to &quot;Large files &amp; duplicates&quot;">​</a></h2><p>The scan summary can list the largest files. The duplicate finder compares hashes for large files you select from that list — useful when reclaiming space from copies.</p><h2 id="file-recovery" tabindex="-1">File recovery <a class="header-anchor" href="#file-recovery" aria-label="Permalink to &quot;File recovery&quot;">​</a></h2><p>Use this mode when you want to <strong>find</strong> files by type under a path and <strong>copy</strong> them elsewhere without changing the source tree.</p><ol><li>Switch the header to <strong>File recovery</strong>.</li><li>Set <strong>Path to scan</strong> (browse, type a path, or pick a volume shortcut).</li><li>Choose <strong>Quick</strong> (metadata + magic) or <strong>Deep</strong> (adds signature carving in an early portion of each file — slower). Optionally restrict <strong>types</strong> (PNG, JPEG, ZIP, PDF, MP4, SQLite, JSON); leave all unchecked to use every built-in signature.</li><li>Click <strong>Run scan</strong>. Progress updates while files are walked.</li><li>In <strong>Browse &amp; select</strong>, use <strong>Preview</strong> on <strong>image</strong> and <strong>video</strong> rows (real files only — not carved hits inside another file). Select rows and <strong>Recover to folder…</strong> to copy into a destination you choose.</li><li><strong>New scan</strong> clears the current results so you can change the source or options.</li></ol><p>Recovery <strong>never writes</strong> to the scanned paths; it only reads and copies into the output folder. <strong>Carved</strong> hits may appear in the list but are not extracted as separate files in the current version. This mode scans a <strong>folder tree</strong>, not raw partitions or filesystem internals — SSDs with TRIM may still limit what is recoverable in practice.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>When in doubt, keep dry-run on and read paths carefully.</li><li>Closing or ignoring “review” items is fine — only selected rows are affected.</li><li>Platform permissions (for example Trash or full disk) may prompt once per session depending on OS settings.</li></ul>',24)])])}const g=a(n,[["render",o]]);export{p as __pageData,g as default};
